_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv1 = (vUv-.5);
dx = GetPixel(vUv+hor) - GetPixel(vUv-hor);
dy = GetPixel(vUv+ver) - GetPixel(vUv-ver);

dz = vec2 (dx.g,dy.g);
ret.g = mix(cloud(uv1+noise(uv1,uTime*0.017)*.25)*0.75,GetPixel(vUv+-.01*dz).g,0.95) - 0.004;
dz = vec2 (dx.r,dy.r);
uv1*=0.5;
ret.r = mix(cloud(uv1+noise(uv1,uTime*0.022)*0.5)*q20,GetPixel(vUv-.01*dz).r,0.9) - 0.004;

float varea = sat(10-20*max(abs(vUv.x-.5),abs(vUv.y-.5)));
ret*=varea;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

  float mask = 0, fog=0, trail = 0;
  vec2 uv1 = (vUvOriginal-0.5)*uAspect.xy + pos;
  vec2 p, q = multiply(uv1, mat2(_qa))/zoom, t=0, uvt;
  vec3 S = 0, C = vec3(1, 2, 3), col, scr, scm;
  for (int i = 0; i < trails; i++)
  {
    float j=i/trails;
    p = q* (1-zz*j);
    p+= 0.03* sin(pow(i+1.,vec2(17,23)/371)*T)*vec2(1,3);
    mask = max(mask,sat(10-300*max(abs(p.x),.75*abs(p.y))));
    col =  (cos(C*14*cos(i))+1)*(1+roam_cos);

    uvt = p + vec2(j,0);
    scr = texture(sampler_pw_noise_lq, fract(.2*uvt));

    uvt += vec2(T*.1,T*(1+j));
    scm = texture(sampler_main, 1.5*uvt.yx/uAspect.xy);

    trail = 1 / length(p / (vec2(1,scm.r*16)));
    trail += q21*mask*scr.r / length(p / (vec2(2,128*scr.g)));
    S += trail *   0.005 * col;

    S += vb/length(p)* (sat(1-pow((BPMtime)%trails-i,2)) +
                       sat(1-pow((BPMtime*2)%trails-i,2))*2*col);

   fog += scm.g* abs(p.x);
   S+= scm.g*0.7;
 }
 ret = sat(q.x)*(C-1)/2  + pow(S,1.5)/trails;
 ret = 1-exp(-1.5*ret+fog/2);
//ret = GetPixel(vUv);

  fragColor = ret;
}
